 * ================================================= */
void example_barrier(void) {
    int *c = (int *)mmap(NULL, sizeof(int), PROT_READ|PROT_WRITE, MAP_SHARED|MAP_ANONYMOUS, -1, 0);
    *c = 0;
    sem_t *m = sem_open("/kf_ex_bm", O_CREAT|O_EXCL, 0644, 1);
    sem_t *b = sem_open("/kf_ex_bb", O_CREAT|O_EXCL, 0644, 0);
    for (int i = 0; i < 2; i++) {
        if (fork() == 0) {
            sem_wait(m); (*c)++; int l = *c; sem_post(m);
            if (l == 2) sem_post(b); else sem_wait(b);
            _exit(0);
        }
    }
    for (int i = 0; i < 2; i++) waitpid(-1, NULL, 0);
    printf("2 passed\n");
    sem_close(m); sem_close(b);
    sem_unlink("/kf_ex_bm"); sem_unlink("/kf_ex_bb");
    munmap(c, sizeof(int));
}
